{
  "name": "ProFilter Builder",
  "description": "A high-end product filter manager and style customizer for e-commerce platforms. Manage slugs, categories, and visual aesthetics with real-time previews."
}

export enum FilterType {
  DROPDOWN = 'dropdown',
  CHECKBOX = 'checkbox',
  RADIO = 'radio',
  COLOR_SWATCH = 'color_swatch'
}

export interface FilterOption {
  id: string;
  label: string;
  count: number;
}

export interface FilterItem {
  id: string;
  label: string;
  slug: string;
  type: FilterType;
  options: FilterOption[];
  enabled: boolean;
}

export interface Mapping {
  id: string;
  type: 'category' | 'attribute' | 'variant';
  name: string;
  slug: string;
}

export interface GlobalStyles {
  backgroundColor: string;
  borderColor: string;
  textColor: string;
  activeBackgroundColor: string;
  activeBorderColor: string;
  borderRadius: string;
}

export type TabType = 'manage' | 'mapping' | 'styling' | 'preview';

import React from 'react';
import { FilterItem, FilterType, GlobalStyles, Mapping } from './types';

export const DEFAULT_FILTERS: FilterItem[] = [
  {
    id: '1',
    label: 'TOG | Temperature',
    slug: 'tog-rating',
    type: FilterType.DROPDOWN,
    enabled: true,
    options: [
      { id: 't1', label: '0.2 TOG', count: 12 },
      { id: 't2', label: '1.0 TOG', count: 45 },
      { id: 't3', label: '2.5 TOG', count: 32 }
    ]
  },
  {
    id: '2',
    label: 'Stage',
    slug: 'stage',
    type: FilterType.DROPDOWN,
    enabled: true,
    options: [
      { id: 's1', label: 'Stage 1 - Newborn & Swaddling', count: 67 },
      { id: 's2', label: 'Stage 2 - Ready to Roll', count: 45 },
      { id: 's3', label: 'Stage 3 - On the Move', count: 41 },
      { id: 's4', label: 'All Stages', count: 58 }
    ]
  },
  {
    id: '3',
    label: 'Fabric',
    slug: 'fabric',
    type: FilterType.DROPDOWN,
    enabled: true,
    options: [
      { id: 'f1', label: 'Organic Cotton', count: 88 },
      { id: 'f2', label: 'Bamboo', count: 22 }
    ]
  }
];

export const DEFAULT_STYLES: GlobalStyles = {
  backgroundColor: '#ffffff',
  borderColor: '#e2e8f0',
  textColor: '#0f172a',
  activeBackgroundColor: '#e2f2f1',
  activeBorderColor: '#0d9488',
  borderRadius: '0.75rem'
};

export const DEFAULT_MAPPINGS: Mapping[] = [
  { id: 'm1', type: 'category', name: 'Sleeping Bags', slug: 'sleeping-bags' },
  { id: 'm2', type: 'attribute', name: 'Color', slug: 'pa_color' },
  { id: 'm3', type: 'variant', name: 'Size', slug: 'attribute_pa_size' }
];

import React, { useState } from 'react';
import { FilterItem, FilterType } from '../types';

interface Props {
  filters: FilterItem[];
  onUpdate: (filters: FilterItem[]) => void;
}

const FilterManager: React.FC<Props> = ({ filters, onUpdate }) => {
  const [editingId, setEditingId] = useState<string | null>(null);

  const toggleFilter = (id: string) => {
    onUpdate(filters.map(f => f.id === id ? { ...f, enabled: !f.enabled } : f));
  };

  const deleteFilter = (id: string) => {
    if (confirm('Are you sure you want to delete this filter?')) {
      onUpdate(filters.filter(f => f.id !== id));
    }
  };

  const addFilter = () => {
    const newFilter: FilterItem = {
      id: Date.now().toString(),
      label: 'New Filter',
      slug: 'new-filter',
      type: FilterType.DROPDOWN,
      enabled: true,
      options: []
    };
    onUpdate([...filters, newFilter]);
    setEditingId(newFilter.id);
  };

  const saveEdit = (id: string, updates: Partial<FilterItem>) => {
    onUpdate(filters.map(f => f.id === id ? { ...f, ...updates } : f));
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <div>
          <h2 className="text-2xl font-bold text-gray-800">Manage Filters</h2>
          <p className="text-gray-500 text-sm">Organize and configure your product selectors.</p>
        </div>
        <button 
          onClick={addFilter}
          className="bg-teal-600 hover:bg-teal-700 text-white px-4 py-2 rounded-lg font-medium transition-colors flex items-center gap-2"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
          Add New Filter
        </button>
      </div>

      <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
        {filters.length === 0 ? (
          <div className="p-12 text-center text-gray-500">No filters added yet. Click "Add New Filter" to begin.</div>
        ) : (
          <ul className="divide-y divide-gray-100">
            {filters.map((filter) => (
              <li key={filter.id} className="p-4 hover:bg-gray-50 transition-colors">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-4">
                    <div className="cursor-grab text-gray-300">
                      <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M3 5a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zM3 10a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zM3 15a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1z" clipRule="evenodd" /></svg>
                    </div>
                    <div>
                      {editingId === filter.id ? (
                        <div className="flex gap-2">
                          <input 
                            className="border border-gray-300 rounded px-2 py-1 text-sm focus:ring-2 focus:ring-teal-500 outline-none"
                            value={filter.label}
                            onChange={(e) => saveEdit(filter.id, { label: e.target.value })}
                            autoFocus
                          />
                          <input 
                            className="border border-gray-300 rounded px-2 py-1 text-sm focus:ring-2 focus:ring-teal-500 outline-none bg-gray-50"
                            value={filter.slug}
                            onChange={(e) => saveEdit(filter.id, { slug: e.target.value })}
                          />
                        </div>
                      ) : (
                        <div className="flex items-center gap-2">
                          <span className="font-semibold text-gray-800">{filter.label}</span>
                          <span className="px-2 py-0.5 bg-gray-100 text-gray-500 text-xs rounded uppercase tracking-wider">{filter.slug}</span>
                        </div>
                      )}
                      <div className="text-xs text-gray-400 mt-1">
                        {filter.options.length} options • {filter.enabled ? 'Enabled' : 'Disabled'}
                      </div>
                    </div>
                  </div>
                  <div className="flex items-center gap-3">
                    <button 
                      onClick={() => setEditingId(editingId === filter.id ? null : filter.id)}
                      className={`px-3 py-1.5 rounded-md text-sm border transition-all ${editingId === filter.id ? 'bg-teal-50 border-teal-200 text-teal-600' : 'hover:bg-gray-50 text-gray-600 border-gray-200'}`}
                    >
                      {editingId === filter.id ? 'Save' : 'Edit'}
                    </button>
                    <button 
                      onClick={() => toggleFilter(filter.id)}
                      className={`px-3 py-1.5 rounded-md text-sm border transition-all ${filter.enabled ? 'bg-white text-gray-600 hover:bg-gray-50' : 'bg-gray-100 text-gray-400'}`}
                    >
                      {filter.enabled ? 'Disable' : 'Enable'}
                    </button>
                    <button 
                      onClick={() => deleteFilter(filter.id)}
                      className="px-3 py-1.5 rounded-md text-sm border border-red-100 text-red-500 hover:bg-red-50 transition-all"
                    >
                      Delete
                    </button>
                  </div>
                </div>
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
};

export default FilterManager;

import React, { useState } from 'react';
import { Mapping } from '../types';

interface Props {
  mappings: Mapping[];
  onUpdate: (mappings: Mapping[]) => void;
}

const CategoryMapping: React.FC<Props> = ({ mappings, onUpdate }) => {
  const [newMapping, setNewMapping] = useState<Partial<Mapping>>({ type: 'category' });

  const addMapping = () => {
    if (!newMapping.name || !newMapping.slug) return;
    onUpdate([...mappings, { 
      id: Date.now().toString(), 
      type: newMapping.type as any, 
      name: newMapping.name as string, 
      slug: newMapping.slug as string 
    }]);
    setNewMapping({ type: 'category', name: '', slug: '' });
  };

  const removeMapping = (id: string) => {
    onUpdate(mappings.filter(m => m.id !== id));
  };

  return (
    <div className="space-y-6">
      <div>
        <h2 className="text-2xl font-bold text-gray-800">Slug Mapping</h2>
        <p className="text-gray-500 text-sm">Define custom URL slugs for your product taxonomies.</p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1 bg-white p-6 rounded-xl border border-gray-200 shadow-sm h-fit">
          <h3 className="text-lg font-semibold mb-4">Add Mapping</h3>
          <div className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Type</label>
              <select 
                className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-teal-500 outline-none"
                value={newMapping.type}
                onChange={(e) => setNewMapping({...newMapping, type: e.target.value as any})}
              >
                <option value="category">Category</option>
                <option value="attribute">Attribute</option>
                <option value="variant">Variant</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Display Name</label>
              <input 
                className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-teal-500 outline-none"
                placeholder="e.g. Size"
                value={newMapping.name || ''}
                onChange={(e) => setNewMapping({...newMapping, name: e.target.value})}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">System Slug</label>
              <input 
                className="w-full border border-gray-300 rounded-lg p-2 focus:ring-2 focus:ring-teal-500 outline-none"
                placeholder="e.g. pa_size"
                value={newMapping.slug || ''}
                onChange={(e) => setNewMapping({...newMapping, slug: e.target.value})}
              />
            </div>
            <button 
              onClick={addMapping}
              className="w-full bg-teal-600 text-white py-2 rounded-lg font-medium hover:bg-teal-700 transition-colors"
            >
              Add Mapping
            </button>
          </div>
        </div>

        <div className="lg:col-span-2 bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
          <table className="w-full text-left">
            <thead className="bg-gray-50 border-b border-gray-100">
              <tr>
                <th className="px-6 py-3 text-xs font-bold text-gray-400 uppercase">Type</th>
                <th className="px-6 py-3 text-xs font-bold text-gray-400 uppercase">Name</th>
                <th className="px-6 py-3 text-xs font-bold text-gray-400 uppercase">Slug</th>
                <th className="px-6 py-3 text-xs font-bold text-gray-400 uppercase text-right">Action</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-100">
              {mappings.map((m) => (
                <tr key={m.id} className="hover:bg-gray-50 transition-colors">
                  <td className="px-6 py-4">
                    <span className={`px-2 py-1 rounded text-xs font-medium ${
                      m.type === 'category' ? 'bg-blue-50 text-blue-600' : 
                      m.type === 'attribute' ? 'bg-purple-50 text-purple-600' : 
                      'bg-orange-50 text-orange-600'
                    }`}>
                      {m.type}
                    </span>
                  </td>
                  <td className="px-6 py-4 font-medium text-gray-700">{m.name}</td>
                  <td className="px-6 py-4 text-gray-500 font-mono text-sm">{m.slug}</td>
                  <td className="px-6 py-4 text-right">
                    <button 
                      onClick={() => removeMapping(m.id)}
                      className="text-red-400 hover:text-red-600 transition-colors"
                    >
                      Remove
                    </button>
                  </td>
                </tr>
              ))}
              {mappings.length === 0 && (
                <tr>
                  <td colSpan={4} className="px-6 py-12 text-center text-gray-400 italic">No mappings defined</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

export default CategoryMapping;

import React, { useState } from 'react';
import { FilterItem, GlobalStyles } from '../types';

interface Props {
  filters: FilterItem[];
  styles: GlobalStyles;
}

const FilterPreview: React.FC<Props> = ({ filters, styles }) => {
  const [openDropdown, setOpenDropdown] = useState<string | null>(null);

  const enabledFilters = filters.filter(f => f.enabled);

  return (
    <div className="space-y-8">
      <div>
        <h2 className="text-2xl font-bold text-gray-800">Live Preview</h2>
        <p className="text-gray-500 text-sm">See how your filters will appear on your storefront.</p>
      </div>

      <div className="bg-white p-8 rounded-2xl border border-gray-100 shadow-xl min-h-[400px]">
        {/* Filter Bar */}
        <div className="flex flex-wrap gap-4 mb-8">
          {enabledFilters.map((filter) => (
            <div key={filter.id} className="relative">
              <button
                onClick={() => setOpenDropdown(openDropdown === filter.id ? null : filter.id)}
                style={{
                  backgroundColor: openDropdown === filter.id ? styles.activeBackgroundColor : styles.backgroundColor,
                  borderColor: openDropdown === filter.id ? styles.activeBorderColor : styles.borderColor,
                  color: styles.textColor,
                  borderRadius: styles.borderRadius
                }}
                className="px-5 py-2.5 border font-medium flex items-center gap-3 transition-all duration-200 hover:shadow-md active:scale-95"
              >
                {filter.label}
                <svg 
                  className={`w-4 h-4 transition-transform duration-200 ${openDropdown === filter.id ? 'rotate-180' : ''}`} 
                  fill="none" stroke="currentColor" viewBox="0 0 24 24"
                >
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M19 9l-7 7-7-7" />
                </svg>
              </button>

              {/* Dropdown Menu */}
              {openDropdown === filter.id && (
                <div 
                  className="absolute top-full left-0 mt-2 w-72 bg-white rounded-xl shadow-2xl border border-gray-100 p-3 z-50 animate-in fade-in slide-in-from-top-2 duration-200"
                  style={{ borderRadius: styles.borderRadius }}
                >
                  <div className="max-h-64 overflow-y-auto custom-scrollbar">
                    {filter.options.map((opt) => (
                      <label key={opt.id} className="flex items-center justify-between p-2.5 hover:bg-gray-50 rounded-lg cursor-pointer transition-colors group">
                        <div className="flex items-center gap-3">
                          <input type="checkbox" className="w-4 h-4 rounded border-gray-300 text-teal-600 focus:ring-teal-500" />
                          <span className="text-sm font-medium text-gray-700 group-hover:text-teal-700">{opt.label}</span>
                        </div>
                        <span className="text-xs font-bold text-gray-400 bg-gray-100 px-2 py-0.5 rounded-full">{opt.count}</span>
                      </label>
                    ))}
                  </div>
                </div>
              )}
            </div>
          ))}

          {/* Sort By Mockup */}
          <div className="ml-auto">
            <button
              style={{ borderRadius: styles.borderRadius }}
              className="px-5 py-2.5 border border-gray-200 font-medium text-gray-500 flex items-center gap-2"
            >
              Sort by
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 9l-7 7-7-7" /></svg>
            </button>
          </div>
        </div>

        {/* Results Info */}
        <div className="text-sm text-gray-500 mb-8 flex items-center gap-2">
          <span className="font-bold text-gray-900">Showing 222 results</span>
          <span className="w-1 h-1 bg-gray-300 rounded-full"></span>
          <span>Category: Sleeping Bags</span>
        </div>

        {/* Product Cards Mockup */}
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
          {[1, 2, 3].map((i) => (
            <div key={i} className="group cursor-pointer">
              <div className="aspect-[4/5] bg-gray-100 rounded-2xl overflow-hidden mb-4 relative shadow-inner">
                <img 
                  src={`https://picsum.photos/seed/${i + 10}/600/750`} 
                  alt="Product" 
                  className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                />
                <div className="absolute top-3 left-3 flex gap-2">
                   {i === 1 && <span className="bg-teal-500 text-white text-[10px] font-bold px-2.5 py-1 rounded-full uppercase tracking-wider">Save $23.85</span>}
                   {i === 3 && <span className="bg-white text-gray-900 text-[10px] font-bold px-2.5 py-1 rounded-full uppercase tracking-wider border border-gray-200">New</span>}
                </div>
              </div>
              <h3 className="font-bold text-gray-800 text-lg mb-1 group-hover:text-teal-600 transition-colors">Premium Organic Swaddle</h3>
              <p className="text-gray-500 text-sm mb-2">1.0 TOG • Organic Cotton</p>
              <div className="flex items-center gap-2">
                <span className="text-teal-600 font-bold">$49.95</span>
                <span className="text-gray-400 text-sm line-through">$72.80</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default FilterPreview;

import React, { useState } from 'react';
import { FilterItem, GlobalStyles, Mapping, TabType } from './types';
import { DEFAULT_FILTERS, DEFAULT_STYLES, DEFAULT_MAPPINGS } from './constants';
import FilterManager from './components/FilterManager';
import CategoryMapping from './components/CategoryMapping';
import StylingOptions from './components/StylingOptions';
import FilterPreview from './components/FilterPreview';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState<TabType>('manage');
  const [filters, setFilters] = useState<FilterItem[]>(DEFAULT_FILTERS);
  const [styles, setStyles] = useState<GlobalStyles>(DEFAULT_STYLES);
  const [mappings, setMappings] = useState<Mapping[]>(DEFAULT_MAPPINGS);

  const tabs: { id: TabType; label: string; icon: React.ReactNode }[] = [
    { 
      id: 'manage', 
      label: 'Manage Filters', 
      icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 6V4m0 2a2 2 0 100 4m0-4a2 2 0 110 4m-6 8a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4m6 6v10m6-2a2 2 0 100-4m0 4a2 2 0 110-4m0 4v2m0-6V4" /></svg>
    },
    { 
      id: 'mapping', 
      label: 'Category Mapping', 
      icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13.828 10.172a4 4 0 00-5.656 0l-4 4a4 4 0 105.656 5.656l1.102-1.101m-.758-4.899a4 4 0 005.656 0l4-4a4 4 0 00-5.656-5.656l-1.1 1.1" /></svg>
    },
    { 
      id: 'styling', 
      label: 'Styling Options', 
      icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 21a4 4 0 01-4-4V5a2 2 0 012-2h4a2 2 0 012 2v12a4 4 0 01-4 4zm0 0h12a2 2 0 002-2v-4a2 2 0 00-2-2h-2.343M11 7.343l1.657-1.657a2 2 0 012.828 0l2.829 2.829a2 2 0 010 2.828l-8.486 8.485M7 17h.01" /></svg>
    },
    { 
      id: 'preview', 
      label: 'Live Preview', 
      icon: <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M15 12a3 3 0 11-6 0 3 3 0 016 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M2.458 12C3.732 7.943 7.523 5 12 5c4.478 0 8.268 2.943 9.542 7-1.274 4.057-5.064 7-9.542 7-4.477 0-8.268-2.943-9.542-7z" /></svg>
    },
  ];

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {/* Header */}
      <header className="bg-white border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-teal-600 rounded-xl flex items-center justify-center shadow-lg shadow-teal-600/20">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M3 4a1 1 0 011-1h16a1 1 0 011 1v2.586a1 1 0 01-.293.707l-6.414 6.414a1 1 0 00-.293.707V17l-4 4v-6.586a1 1 0 00-.293-.707L3.293 7.293A1 1 0 013 6.586V4z" />
              </svg>
            </div>
            <div>
              <h1 className="text-xl font-bold text-slate-800 leading-none">ProFilter Builder</h1>
              <span className="text-[10px] font-bold text-teal-600 uppercase tracking-widest">v2.5 Professional</span>
            </div>
          </div>

          <div className="flex items-center gap-4">
            <div className="flex bg-slate-100 p-1 rounded-xl">
              {tabs.map((tab) => (
                <button
                  key={tab.id}
                  onClick={() => setActiveTab(tab.id)}
                  className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-semibold transition-all duration-200 ${
                    activeTab === tab.id 
                    ? 'bg-white text-teal-600 shadow-sm' 
                    : 'text-slate-500 hover:text-slate-800'
                  }`}
                >
                  {tab.icon}
                  <span className="hidden sm:inline">{tab.label}</span>
                </button>
              ))}
            </div>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="flex-1 max-w-7xl mx-auto w-full px-4 py-10">
        <div className="animate-in fade-in slide-in-from-bottom-2 duration-500">
          {activeTab === 'manage' && (
            <FilterManager filters={filters} onUpdate={setFilters} />
          )}
          {activeTab === 'mapping' && (
            <CategoryMapping mappings={mappings} onUpdate={setMappings} />
          )}
          {activeTab === 'styling' && (
            <StylingOptions styles={styles} onUpdate={setStyles} />
          )}
          {activeTab === 'preview' && (
            <FilterPreview filters={filters} styles={styles} />
          )}
        </div>
      </main>

      {/* Footer Actions */}
      <footer className="bg-white border-t border-slate-200 py-4 fixed bottom-0 w-full">
        <div className="max-w-7xl mx-auto px-4 flex justify-between items-center">
          <p className="text-sm text-slate-400">All changes are saved to your local session.</p>
          <div className="flex gap-3">
            <button 
              onClick={() => {
                setFilters(DEFAULT_FILTERS);
                setStyles(DEFAULT_STYLES);
                setMappings(DEFAULT_MAPPINGS);
              }}
              className="px-6 py-2 border border-slate-200 rounded-xl text-sm font-bold text-slate-600 hover:bg-slate-50 transition-colors"
            >
              Reset to Defaults
            </button>
