import React, { useState } from 'react';
import { FilterItem, FilterType, FilterOption } from '../types';

interface Props {
  filters: FilterItem[];
  onUpdate: (filters: FilterItem[]) => void;
}

const FilterManager: React.FC<Props> = ({ filters, onUpdate }) => {
  const [editingId, setEditingId] = useState<string | null>(null);

  const addFilter = () => {
    const newFilter: FilterItem = {
      id: Date.now().toString(),
      label: 'New Filter Group',
      slug: 'new_filter_' + Date.now().toString().slice(-4),
      type: FilterType.DROPDOWN,
      enabled: true,
      options: [
        { id: 'opt1', label: 'Value 1', count: 0 },
        { id: 'opt2', label: 'Value 2', count: 0 }
      ]
    };
    onUpdate([...filters, newFilter]);
    setEditingId(newFilter.id);
  };

  const updateFilter = (id: string, updates: Partial<FilterItem>) => {
    onUpdate(filters.map(f => f.id === id ? { ...f, ...updates } : f));
  };

  const addOption = (filterId: string) => {
    const filter = filters.find(f => f.id === filterId);
    if (!filter) return;
    const newOption: FilterOption = {
      id: Date.now().toString(),
      label: 'New Value',
      count: 0
    };
    updateFilter(filterId, { options: [...filter.options, newOption] });
  };

  const updateOption = (filterId: string, optionId: string, label: string) => {
    const filter = filters.find(f => f.id === filterId);
    if (!filter) return;
    updateFilter(filterId, {
      options: filter.options.map(opt => opt.id === optionId ? { ...opt, label } : opt)
    });
  };

  const removeFilter = (id: string) => {
    if (confirm('Delete this filter group?')) {
      onUpdate(filters.filter(f => f.id !== id));
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-end">
        <div>
          <h2 className="text-xl font-bold text-gray-800">Available Filters</h2>
          <p className="text-gray-500 text-sm">Create and arrange your storefront filter widgets.</p>
        </div>
        <button 
          onClick={addFilter}
          className="bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-lg font-bold shadow-lg shadow-blue-600/20 transition-all flex items-center gap-2"
        >
          <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 4v16m8-8H4" /></svg>
          Add New Filter Group
        </button>
      </div>

      <div className="space-y-4">
        {filters.map((filter) => (
          <div key={filter.id} className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden transition-all hover:border-blue-200">
            <div className="p-5 flex items-start justify-between">
              <div className="flex-1">
                <div className="flex items-center gap-4 mb-4">
                  <div className="cursor-move text-gray-300 hover:text-gray-500">
                    <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M3 5a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zM3 10a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1zM3 15a1 1 0 011-1h12a1 1 0 110 2H4a1 1 0 01-1-1z" clipRule="evenodd" /></svg>
                  </div>
                  <div className="grid grid-cols-2 gap-4 flex-1 max-w-2xl">
                    <div>
                      <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-1">Display Label</label>
                      <input 
                        className="w-full bg-gray-50 border-none rounded-lg px-3 py-2 text-sm font-semibold focus:ring-2 focus:ring-blue-500 transition-all"
                        value={filter.label}
                        onChange={(e) => updateFilter(filter.id, { label: e.target.value })}
                      />
                    </div>
                    <div>
                      <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-1">Taxonomy / Attribute Slug</label>
                      <input 
                        className="w-full bg-gray-50 border-none rounded-lg px-3 py-2 text-sm font-mono text-blue-600 focus:ring-2 focus:ring-blue-500 transition-all"
                        value={filter.slug}
                        onChange={(e) => updateFilter(filter.id, { slug: e.target.value })}
                      />
                    </div>
                  </div>
                </div>

                {/* Option Editor */}
                <div className="pl-9 space-y-2">
                  <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-wider">Manual Options (Slugs)</label>
                  <div className="flex flex-wrap gap-2">
                    {filter.options.map((opt) => (
                      <div key={opt.id} className="flex items-center bg-gray-100 rounded-lg p-1 group">
                        <input 
                          className="bg-transparent border-none px-2 py-1 text-xs font-medium focus:ring-0 w-24"
                          value={opt.label}
                          onChange={(e) => updateOption(filter.id, opt.id, e.target.value)}
                        />
                        <button 
                          onClick={() => updateFilter(filter.id, { options: filter.options.filter(o => o.id !== opt.id) })}
                          className="text-gray-400 hover:text-red-500 p-1 opacity-0 group-hover:opacity-100 transition-opacity"
                        >
                          <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" /></svg>
                        </button>
                      </div>
                    ))}
                    <button 
                      onClick={() => addOption(filter.id)}
                      className="text-xs font-bold text-blue-600 hover:bg-blue-50 px-3 py-1.5 rounded-lg border border-dashed border-blue-200"
                    >
                      + Add Item
                    </button>
                  </div>
                </div>
              </div>

              <div className="flex flex-col gap-2 ml-4">
                 <div className="flex items-center gap-2 mb-2">
                    <span className="text-[10px] font-bold text-gray-400">STATUS</span>
                    <button 
                      onClick={() => updateFilter(filter.id, { enabled: !filter.enabled })}
                      className={`w-10 h-5 rounded-full relative transition-colors ${filter.enabled ? 'bg-green-500' : 'bg-gray-300'}`}
                    >
                      <div className={`absolute top-0.5 w-4 h-4 bg-white rounded-full transition-all ${filter.enabled ? 'left-5.5' : 'left-0.5'}`} style={{ left: filter.enabled ? '22px' : '2px' }} />
                    </button>
                 </div>
                 <button 
                  onClick={() => removeFilter(filter.id)}
                  className="p-2 text-gray-400 hover:text-red-500 transition-colors"
                  title="Delete Group"
                 >
                   <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" /></svg>
                 </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default FilterManager;

import React, { useState } from 'react';
