    if (!newMapping.name || !newMapping.slug) return;
    onUpdate([...mappings, { 
      id: Date.now().toString(), 
      type: newMapping.type as any, 
      name: newMapping.name as string, 
      slug: newMapping.slug as string 
    }]);
    setNewMapping({ ...newMapping, name: '', slug: '' });
  };

  const quickAdd = (type: any, name: string, slug: string) => {
    if (mappings.find(m => m.slug === slug)) return;
    onUpdate([...mappings, { id: Date.now().toString(), type, name, slug }]);
  };

  return (
    <div className="space-y-8">
