import React, { useState } from 'react';
import { FilterItem, GlobalStyles } from '../types';

interface Props {
  filters: FilterItem[];
  styles: GlobalStyles;
}

const FilterPreview: React.FC<Props> = ({ filters, styles }) => {
  const [openDropdown, setOpenDropdown] = useState<string | null>(null);
  const [selectedValues, setSelectedValues] = useState<Record<string, string[]>>({});

  const toggleValue = (filterId: string, value: string) => {
    const current = selectedValues[filterId] || [];
    if (current.includes(value)) {
      setSelectedValues({ ...selectedValues, [filterId]: current.filter(v => v !== value) });
    } else {
      setSelectedValues({ ...selectedValues, [filterId]: [...current, value] });
    }
  };

  const enabledFilters = filters.filter(f => f.enabled);

  return (
    <div className="space-y-8 pb-12">
      <div className="bg-white rounded-3xl shadow-2xl overflow-hidden border border-gray-100 min-h-[600px] flex flex-col">
        {/* Preview Header */}
        <div className="bg-gray-50 px-8 py-4 border-b border-gray-100 flex items-center justify-between">
           <div className="flex items-center gap-2">
              <div className="flex gap-1.5">
                 <div className="w-2 h-2 rounded-full bg-red-400"></div>
                 <div className="w-2 h-2 rounded-full bg-yellow-400"></div>
                 <div className="w-2 h-2 rounded-full bg-green-400"></div>
              </div>
              <span className="ml-4 text-[10px] font-bold text-gray-400 tracking-widest uppercase">Your Storefront (Preview)</span>
           </div>
           <div className="text-[10px] bg-white px-3 py-1 rounded-full border border-gray-200 text-gray-500 font-bold">
              SHOP.YOURDOMAIN.COM
           </div>
        </div>

        {/* Filter Toolbar Area */}
        <div className="p-8 pb-0">
          <div className="flex flex-wrap gap-3 mb-8 items-center">
            {enabledFilters.map((filter) => {
              const countSelected = selectedValues[filter.id]?.length || 0;
              const isActive = openDropdown === filter.id || countSelected > 0;

              return (
                <div key={filter.id} className="relative">
                  <button
                    onClick={() => setOpenDropdown(openDropdown === filter.id ? null : filter.id)}
                    style={{
                      backgroundColor: isActive ? styles.activeBackgroundColor : styles.backgroundColor,
                      borderColor: isActive ? styles.activeBorderColor : styles.borderColor,
                      color: styles.textColor,
                      borderRadius: styles.borderRadius
                    }}
                    className={`px-5 py-2.5 border font-semibold flex items-center gap-3 transition-all duration-300 shadow-sm hover:shadow-md ${isActive ? 'ring-2 ring-blue-500/10' : ''}`}
                  >
                    <span className="text-sm">{filter.label}</span>
                    {countSelected > 0 && (
                      <span className="bg-blue-600 text-white text-[10px] w-5 h-5 rounded-full flex items-center justify-center font-bold">
                        {countSelected}
                      </span>
                    )}
                    <svg 
                      className={`w-3.5 h-3.5 transition-transform duration-300 ${openDropdown === filter.id ? 'rotate-180' : ''}`} 
