import React, { useState } from 'react';
import { FilterItem, FilterType, FilterOption } from '../types';

interface Props {
  filters: FilterItem[];
  onUpdate: (filters: FilterItem[]) => void;
}

const FilterManager: React.FC<Props> = ({ filters, onUpdate }) => {
  const addFilter = () => {
    const newFilter: FilterItem = {
      id: Date.now().toString(),
      label: 'New Filter Group',
      slug: 'new_filter_' + Date.now().toString().slice(-4),
      type: FilterType.DROPDOWN,
      enabled: true,
      options: [
        { id: 'opt1', label: 'Value 1', count: 0 }
      ]
    };
    onUpdate([...filters, newFilter]);
  };

  const updateFilter = (id: string, updates: Partial<FilterItem>) => {
    onUpdate(filters.map(f => f.id === id ? { ...f, ...updates } : f));
  };

  const addOption = (filterId: string) => {
    const filter = filters.find(f => f.id === filterId);
    if (!filter) return;
    const newOption: FilterOption = {
      id: Date.now().toString(),
      label: 'New Value',
      count: 0
    };
    updateFilter(filterId, { options: [...filter.options, newOption] });
  };

  const updateOption = (filterId: string, optionId: string, label: string) => {
    const filter = filters.find(f => f.id === filterId);
    if (!filter) return;
    updateFilter(filterId, {
      options: filter.options.map(opt => opt.id === optionId ? { ...opt, label } : opt)
    });
  };

  const removeFilter = (id: string) => {
    if (confirm('Delete this filter group? This will remove it from the frontend.')) {
      onUpdate(filters.filter(f => f.id !== id));
    }
  };

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
        <div className="lg:col-span-3 space-y-6">
