                      </div>
                      <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 flex-1">
                        <div>
                          <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-wider mb-1">Display Label</label>
                          <input 
                            className="w-full bg-gray-50 border-gray-100 border rounded-lg px-3 py-2 text-sm font-semibold focus:ring-2 focus:ring-blue-500 outline-none transition-all"
                            value={filter.label}
                            onChange={(e) => updateFilter(filter.id, { label: e.target.value })}
                          />
                        </div>
