  filters: FilterItem[];
  styles: GlobalStyles;
}

const FilterPreview: React.FC<Props> = ({ filters, styles }) => {
  const [openDropdown, setOpenDropdown] = useState<string | null>(null);
  const [selectedValues, setSelectedValues] = useState<Record<string, string[]>>({});
  const [isLoading, setIsLoading] = useState(false);
  const [filteredProducts, setFilteredProducts] = useState<Product[]>(MOCK_PRODUCTS);

  const enabledFilters = filters.filter(f => f.enabled);

  // Dynamic Filtering Logic
  useEffect(() => {
    setIsLoading(true);
    const timer = setTimeout(() => {
      let results = MOCK_PRODUCTS;

      Object.entries(selectedValues).forEach(([filterId, values]) => {
        if (values.length === 0) return;

        const filter = filters.find(f => f.id === filterId);
        if (!filter) return;

        results = results.filter(product => {
          const productAttr = product.attributes[filter.slug];
          return values.includes(productAttr);
        });
      });

      setFilteredProducts(results);
      setIsLoading(false);
    }, 600); // Simulated AJAX delay

    return () => clearTimeout(timer);
  }, [selectedValues, filters]);

  const toggleValue = (filterId: string, value: string) => {
    const current = selectedValues[filterId] || [];
    if (current.includes(value)) {
      setSelectedValues({ ...selectedValues, [filterId]: current.filter(v => v !== value) });
    } else {
      setSelectedValues({ ...selectedValues, [filterId]: [...current, value] });
    }
  };

  return (
    <div className="space-y-8 pb-12">
      <div className="bg-white rounded-3xl shadow-2xl overflow-hidden border border-gray-100 min-h-[700px] flex flex-col relative">
        {/* Browser Mockup Header */}
        <div className="bg-gray-50 px-8 py-4 border-b border-gray-100 flex items-center justify-between">
           <div className="flex items-center gap-2">
              <div className="flex gap-1.5">
                 <div className="w-2.5 h-2.5 rounded-full bg-red-400"></div>
                 <div className="w-2.5 h-2.5 rounded-full bg-yellow-400"></div>
                 <div className="w-2.5 h-2.5 rounded-full bg-green-400"></div>
              </div>
              <span className="ml-4 text-[10px] font-bold text-gray-400 tracking-widest uppercase">Frontend Shop Preview</span>
           </div>
           <div className="text-[10px] bg-white px-4 py-1.5 rounded-full border border-gray-200 text-gray-500 font-bold shadow-sm">
              HTTPS://YOURSTORE.COM/SHOP
           </div>
        </div>

        {/* Dynamic Toolbar */}
        <div className="p-8 pb-0">
          <div className="flex flex-wrap gap-4 mb-6 items-center">
            {enabledFilters.map((filter) => {
              const countSelected = selectedValues[filter.id]?.length || 0;
              const isActive = openDropdown === filter.id || countSelected > 0;

              return (
                <div key={filter.id} className="relative">
                  <button
                    onClick={() => setOpenDropdown(openDropdown === filter.id ? null : filter.id)}
                    style={{
                      backgroundColor: isActive ? styles.activeBackgroundColor : styles.backgroundColor,
                      borderColor: isActive ? styles.activeBorderColor : styles.borderColor,
                      color: styles.textColor,
                      borderRadius: styles.borderRadius
                    }}
                    className={`px-6 py-3 border font-bold flex items-center gap-3 transition-all duration-300 shadow-sm hover:shadow-md ${isActive ? 'ring-4 ring-blue-500/10' : ''}`}
                  >
                    <span className="text-sm">{filter.label}</span>
                    {countSelected > 0 && (
                      <span className="bg-blue-600 text-white text-[10px] w-5 h-5 rounded-full flex items-center justify-center font-black">
                        {countSelected}
                      </span>
                    )}
                    <svg className={`w-4 h-4 transition-transform duration-300 ${openDropdown === filter.id ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7" /></svg>
                  </button>

                  {openDropdown === filter.id && (
                    <div 
                      className="absolute top-full left-0 mt-3 w-72 bg-white rounded-2xl shadow-2xl border border-gray-100 p-4 z-50 animate-in fade-in zoom-in-95 duration-200 origin-top-left"
                      style={{ borderRadius: styles.borderRadius }}
                    >
                      <div className="space-y-1 max-h-72 overflow-y-auto custom-scrollbar">
                        {filter.options.map((opt) => (
                          <label key={opt.id} className="flex items-center justify-between p-3 hover:bg-gray-50 rounded-xl cursor-pointer group transition-colors">
                            <div className="flex items-center gap-3">
                              <input 
                                type="checkbox" 
                                className="w-5 h-5 rounded border-gray-300 text-blue-600 focus:ring-blue-500 cursor-pointer" 
                                checked={selectedValues[filter.id]?.includes(opt.label)}
                                onChange={() => toggleValue(filter.id, opt.label)}
                              />
                              <span className="text-sm font-bold text-gray-700 group-hover:text-blue-700 transition-colors">{opt.label}</span>
                            </div>
                            <span className="text-[10px] font-black text-gray-400 bg-gray-100 px-2 py-1 rounded-lg">{opt.count || 0}</span>
                          </label>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              );
            })}

            <div className="ml-auto flex items-center gap-4">
               <span className="text-xs font-bold text-gray-400">{filteredProducts.length} Products Found</span>
