               </button>
            </div>
          </div>

          {/* Active Filter Chips */}
          <div className="flex items-center gap-3 mb-10 min-h-[40px]">
            {(Object.entries(selectedValues) as [string, string[]][]).flatMap(([fid, vals]) => 
               vals.map(v => (
                 <div key={fid+v} className="bg-blue-600 text-white px-4 py-2 rounded-full text-xs font-bold flex items-center gap-3 shadow-lg shadow-blue-600/20 animate-in zoom-in">
