                    <button onClick={() => toggleValue(fid, v)} className="hover:text-blue-100 transition-colors">
                       <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" /></svg>
                    </button>
                 </div>
               ))
            )}
            {(Object.values(selectedValues) as string[][]).some(v => v.length > 0) && (
               <button onClick={() => setSelectedValues({})} className="text-xs font-black text-red-500 hover:text-red-700 ml-2 transition-colors uppercase tracking-widest">Reset All</button>
            )}
          </div>
        </div>

        {/* Product Content Area */}
        <div className="flex-1 px-8 pb-12 relative">
          {isLoading && (
            <div className="absolute inset-0 bg-white/60 backdrop-blur-[2px] z-10 flex items-center justify-center animate-in fade-in duration-300">
               <div className="flex flex-col items-center gap-4">
                  <div className="w-12 h-12 border-4 border-blue-100 border-t-blue-600 rounded-full animate-spin"></div>
                  <span className="text-sm font-bold text-blue-600 tracking-widest uppercase">Updating Catalog...</span>
               </div>
            </div>
          )}

          {filteredProducts.length > 0 ? (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
