import React, { useState, useEffect } from 'react';
import { FilterItem, GlobalStyles, Mapping, TabType } from './types';
import { DEFAULT_FILTERS, DEFAULT_STYLES, DEFAULT_MAPPINGS } from './constants';
import FilterManager from './components/FilterManager';
import CategoryMapping from './components/CategoryMapping';
import StylingOptions from './components/StylingOptions';
import FilterPreview from './components/FilterPreview';

interface AppProps {
  isFrontendView?: boolean;
}

const App: React.FC<AppProps> = ({ isFrontendView = false }) => {
  const [activeTab, setActiveTab] = useState<TabType>('manage');
  const [filters, setFilters] = useState<FilterItem[]>(DEFAULT_FILTERS);
  const [styles, setStyles] = useState<GlobalStyles>(DEFAULT_STYLES);
  const [mappings, setMappings] = useState<Mapping[]>(DEFAULT_MAPPINGS);
  const [showSavedToast, setShowSavedToast] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  // Persistence Logic
  useEffect(() => {
    const savedFilters = localStorage.getItem('pf_filters');
    const savedStyles = localStorage.getItem('pf_styles');
    const savedMappings = localStorage.getItem('pf_mappings');

    if (savedFilters) setFilters(JSON.parse(savedFilters));
    if (savedStyles) setStyles(JSON.parse(savedStyles));
    if (savedMappings) setMappings(JSON.parse(savedMappings));
  }, []);

  const handleSave = () => {
    setIsSaving(true);
    setTimeout(() => {
      localStorage.setItem('pf_filters', JSON.stringify(filters));
      localStorage.setItem('pf_styles', JSON.stringify(styles));
      localStorage.setItem('pf_mappings', JSON.stringify(mappings));
      setIsSaving(false);
      setShowSavedToast(true);
      setTimeout(() => setShowSavedToast(false), 3000);
    }, 800);
  };

  // IF FRONTEND: Only show the Filter Shop
  if (isFrontendView) {
    return (
      <div className="profilter-frontend-app py-4">
        <FilterPreview filters={filters} styles={styles} hideBrowserMockup={true} />
      </div>
