import React, { useState, useEffect } from 'react';
import { FilterItem, GlobalStyles } from '../types';

interface Product {
  id: number;
  name: string;
  category: string;
  price: number;
  oldPrice: number;
  image: string;
  attributes: Record<string, string>;
}

const MOCK_PRODUCTS: Product[] = [
  { id: 1, name: "Premium Cotton Swaddle", category: "Sleeping Bags", price: 59, oldPrice: 79, image: "https://picsum.photos/seed/p1/600/800", attributes: { "tog-rating": "1.0 TOG", "stage": "Stage 1 - Newborn & Swaddling", "fabric": "Organic Cotton" } },
  { id: 2, name: "Ready-to-Roll Transition Bag", category: "Sleeping Bags", price: 65, oldPrice: 85, image: "https://picsum.photos/seed/p2/600/800", attributes: { "tog-rating": "2.5 TOG", "stage": "Stage 2 - Ready to Roll", "fabric": "Bamboo" } },
  { id: 3, name: "Lightweight Summer Romper", category: "Rompers", price: 34, oldPrice: 45, image: "https://picsum.photos/seed/p3/600/800", attributes: { "tog-rating": "0.2 TOG", "stage": "Stage 3 - On the Move", "fabric": "Organic Cotton" } },
  { id: 4, name: "Winter Warmth Sleep Suit", category: "Sleep Suits", price: 89, oldPrice: 110, image: "https://picsum.photos/seed/p4/600/800", attributes: { "tog-rating": "2.5 TOG", "stage": "All Stages", "fabric": "Organic Cotton" } },
  { id: 5, name: "Bamboo Transition Suit", category: "Sleep Suits", price: 72, oldPrice: 90, image: "https://picsum.photos/seed/p5/600/800", attributes: { "tog-rating": "1.0 TOG", "stage": "Stage 2 - Ready to Roll", "fabric": "Bamboo" } },
  { id: 6, name: "Newborn Starter Pack", category: "Kits", price: 120, oldPrice: 150, image: "https://picsum.photos/seed/p6/600/800", attributes: { "tog-rating": "1.0 TOG", "stage": "Stage 1 - Newborn & Swaddling", "fabric": "Organic Cotton" } },
];

interface Props {
  filters: FilterItem[];
  styles: GlobalStyles;
  hideBrowserMockup?: boolean;
}

const FilterPreview: React.FC<Props> = ({ filters, styles, hideBrowserMockup = false }) => {
  const [openDropdown, setOpenDropdown] = useState<string | null>(null);
  const [selectedValues, setSelectedValues] = useState<Record<string, string[]>>({});
  const [isLoading, setIsLoading] = useState(false);
  const [filteredProducts, setFilteredProducts] = useState<Product[]>(MOCK_PRODUCTS);

  const enabledFilters = filters.filter(f => f.enabled);

  useEffect(() => {
    setIsLoading(true);
    const timer = setTimeout(() => {
      let results = MOCK_PRODUCTS;
      Object.entries(selectedValues).forEach(([filterId, values]) => {
        if (values.length === 0) return;
        const filter = filters.find(f => f.id === filterId);
        if (!filter) return;
        results = results.filter(product => {
          const productAttr = product.attributes[filter.slug];
          return values.includes(productAttr);
        });
      });
      setFilteredProducts(results);
      setIsLoading(false);
    }, 600);
    return () => clearTimeout(timer);
  }, [selectedValues, filters]);

  const toggleValue = (filterId: string, value: string) => {
    const current = selectedValues[filterId] || [];
    if (current.includes(value)) {
      setSelectedValues({ ...selectedValues, [filterId]: current.filter(v => v !== value) });
    } else {
      setSelectedValues({ ...selectedValues, [filterId]: [...current, value] });
    }
  };

  const Content = (
    <div className="flex flex-col min-h-[700px]">
        {/* Dynamic Toolbar */}
        <div className="pb-8">
          <div className="flex flex-wrap gap-4 mb-6 items-center">
            {enabledFilters.map((filter) => {
              const countSelected = selectedValues[filter.id]?.length || 0;
              const isActive = openDropdown === filter.id || countSelected > 0;

              return (
                <div key={filter.id} className="relative">
                  <button
                    onClick={() => setOpenDropdown(openDropdown === filter.id ? null : filter.id)}
                    style={{
                      backgroundColor: isActive ? styles.activeBackgroundColor : styles.backgroundColor,
                      borderColor: isActive ? styles.activeBorderColor : styles.borderColor,
                      color: styles.textColor,
                      borderRadius: styles.borderRadius
                    }}
                    className={`px-6 py-3 border font-black flex items-center gap-3 transition-all duration-300 shadow-sm hover:shadow-md ${isActive ? 'ring-4 ring-blue-500/10' : ''}`}
                  >
                    <span className="text-sm">{filter.label}</span>
                    {countSelected > 0 && (
                      <span className="bg-blue-600 text-white text-[10px] w-5 h-5 rounded-full flex items-center justify-center font-black">
                        {countSelected}
                      </span>
                    )}
                    <svg className={`w-4 h-4 transition-transform duration-300 ${openDropdown === filter.id ? 'rotate-180' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M19 9l-7 7-7-7" /></svg>
                  </button>

                  {openDropdown === filter.id && (
                    <div 
                      className="absolute top-full left-0 mt-3 w-72 bg-white rounded-2xl shadow-2xl border border-gray-100 p-4 z-50 animate-in fade-in zoom-in-95 duration-200 origin-top-left"
                      style={{ borderRadius: styles.borderRadius }}
                    >
                      <div className="space-y-1 max-h-72 overflow-y-auto">
                        {filter.options.map((opt) => (
                          <label key={opt.id} className="flex items-center justify-between p-3 hover:bg-gray-50 rounded-xl cursor-pointer group transition-colors">
                            <div className="flex items-center gap-3">
                              <input 
                                type="checkbox" 
                                className="w-5 h-5 rounded border-gray-300 text-blue-600 focus:ring-blue-500" 
                                checked={selectedValues[filter.id]?.includes(opt.label)}
                                onChange={() => toggleValue(filter.id, opt.label)}
                              />
                              <span className="text-sm font-bold text-gray-700 group-hover:text-blue-700">{opt.label}</span>
                            </div>
                            <span className="text-[10px] font-black text-gray-400 bg-gray-100 px-2 py-1 rounded-lg">{opt.count || 0}</span>
                          </label>
                        ))}
                      </div>
                    </div>
                  )}
                </div>
              );
            })}

            <div className="ml-auto flex items-center gap-4">
               <span className="text-xs font-bold text-gray-400">{filteredProducts.length} Results</span>
            </div>
          </div>

          <div className="flex flex-wrap items-center gap-3 mb-4 min-h-[40px]">
            {(Object.entries(selectedValues) as [string, string[]][]).flatMap(([fid, vals]) => 
               vals.map(v => (
                 <div key={fid+v} className="bg-blue-600 text-white px-4 py-2 rounded-full text-[10px] font-black flex items-center gap-3 shadow-lg shadow-blue-600/20">
                    {v.toUpperCase()}
                    <button onClick={() => toggleValue(fid, v)} className="hover:text-blue-100 transition-colors">
                       <svg className="w-3 h-3" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clipRule="evenodd" /></svg>
                    </button>
                 </div>
               ))
            )}
            {(Object.values(selectedValues) as string[][]).some(v => v.length > 0) && (
               <button onClick={() => setSelectedValues({})} className="text-[10px] font-black text-red-500 uppercase tracking-widest ml-2">Clear Filters</button>
            )}
          </div>
        </div>

        {/* Product Grid */}
        <div className="flex-1 relative">
          {isLoading && (
            <div className="absolute inset-0 bg-white/40 backdrop-blur-[1px] z-10 flex items-center justify-center">
               <div className="w-10 h-10 border-4 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
            </div>
          )}

          {filteredProducts.length > 0 ? (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
              {filteredProducts.map((p) => (
                <div key={p.id} className="group animate-in fade-in duration-500">
                   <div className="aspect-[3/4] rounded-[2rem] overflow-hidden bg-gray-100 shadow-xl relative ring-1 ring-gray-200">
                      <img src={p.image} alt={p.name} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
                      <div className="absolute top-4 left-4">
                         <span className="bg-white px-3 py-1 rounded-full text-[10px] font-black uppercase text-gray-900 shadow-sm">{p.attributes["tog-rating"]}</span>
                      </div>
                      <div className="absolute bottom-0 inset-x-0 p-5 translate-y-full group-hover:translate-y-0 transition-all duration-400">
                         <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-2xl text-sm">ADD TO CART</button>
                      </div>
                   </div>
                   <div className="mt-6 text-center">
                      <h3 className="text-sm font-black text-gray-900 mb-1 group-hover:text-blue-600 uppercase tracking-tight">{p.name}</h3>
                      <div className="flex items-center justify-center gap-3">
                         <span className="text-xl font-black text-blue-600">${p.price}.00</span>
                         <span className="text-sm text-gray-300 line-through font-bold">${p.oldPrice}.00</span>
                      </div>
                   </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="h-[400px] flex flex-col items-center justify-center text-center">
               <h3 className="text-xl font-black text-gray-900 mb-2">NO PRODUCTS FOUND</h3>
               <button onClick={() => setSelectedValues({})} className="mt-4 text-blue-600 font-black uppercase text-xs tracking-widest">Reset Selections</button>
            </div>
          )}
        </div>
    </div>
  );

  if (hideBrowserMockup) {
    return Content;
  }

  return (
    <div className="bg-white rounded-3xl shadow-2xl overflow-hidden border border-gray-100 min-h-[700px] flex flex-col relative">
        <div className="bg-gray-50 px-8 py-4 border-b border-gray-100 flex items-center justify-between">
           <div className="flex items-center gap-2">
              <div className="flex gap-1.5">
                 <div className="w-2.5 h-2.5 rounded-full bg-red-400"></div>
                 <div className="w-2.5 h-2.5 rounded-full bg-yellow-400"></div>
                 <div className="w-2.5 h-2.5 rounded-full bg-green-400"></div>
              </div>
              <span className="ml-4 text-[10px] font-bold text-gray-400 tracking-widest uppercase tracking-tighter">Live Frontend Preview</span>
           </div>
           <div className="text-[10px] bg-white px-4 py-1.5 rounded-full border border-gray-200 text-gray-500 font-bold shadow-sm">
              SHOP.YOURWEBSITE.COM
           </div>
        </div>
        <div className="p-8 flex-1">
          {Content}
        </div>
    </div>
  );
};

export default FilterPreview;

