  const [mappings, setMappings] = useState<Mapping[]>(DEFAULT_MAPPINGS);
  const [showSavedToast, setShowSavedToast] = useState(false);
  const [isSaving, setIsSaving] = useState(false);

  useEffect(() => {
    const savedFilters = localStorage.getItem('pf_filters');
    const savedStyles = localStorage.getItem('pf_styles');
    const savedMappings = localStorage.getItem('pf_mappings');

    if (savedFilters) setFilters(JSON.parse(savedFilters));
    if (savedStyles) setStyles(JSON.parse(savedStyles));
    if (savedMappings) setMappings(JSON.parse(savedMappings));
